import{_ as E}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as i,c as A,f as a,q as o,D as s,O as n,j as p,g as l,k as t,X as d}from"./chunks/runtime-core.esm-bundler.DoiTk7Jm.js";const k=JSON.parse('{"title":"AI 辅助代码评审 (Code Review) 实战清单：打造智能初筛防线","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/工具提效/AI辅助代码评审清单.md","filePath":"column/AIFuture/工具提效/AI辅助代码评审清单.md","lastUpdated":1781695591000}'),b={name:"column/AIFuture/工具提效/AI辅助代码评审清单.md"};function u(B,e,g,h,m,f){const c=i("ArticleMetadata"),r=i("Mermaid");return a(),A("div",null,[e[2]||(e[2]=o("h1",{id:"ai-辅助代码评审-code-review-实战清单-打造智能初筛防线",tabindex:"-1"},[l("AI 辅助代码评审 (Code Review) 实战清单：打造智能初筛防线 "),o("a",{class:"header-anchor",href:"#ai-辅助代码评审-code-review-实战清单-打造智能初筛防线","aria-label":'Permalink to "AI 辅助代码评审 (Code Review) 实战清单：打造智能初筛防线"'},"​")],-1)),s(c),e[3]||(e[3]=n('<p>在现代软件工程中，代码评审（Code Review, CR）是保障代码质量的最后一道防线，但也往往是研发流程中最耗时的瓶颈。引入 AI 辅助代码评审，其核心定位是 <strong>“不知疲倦的初筛扫描仪”</strong>，而非最终的决策者。</p><blockquote><p>💡 <strong>核心认知：</strong><strong>让 AI 扩大检查面（广度与细节），让工程师判断风险是否成立（深度与业务）。</strong> AI 负责找出“潜在的坏味道”，人类负责拍板“是否需要修改”。</p></blockquote><h2 id="一、能力矩阵-ai-在-cr-中的适用边界" tabindex="-1">一、能力矩阵：AI 在 CR 中的适用边界 <a class="header-anchor" href="#一、能力矩阵-ai-在-cr-中的适用边界" aria-label="Permalink to &quot;一、能力矩阵：AI 在 CR 中的适用边界&quot;">​</a></h2><p>不要期望 AI 能理解复杂的商业逻辑或长期的架构演进规划。将其能力用在刀刃上：</p><table tabindex="0"><thead><tr><th style="text-align:left;">审查维度</th><th style="text-align:center;">AI 胜任度</th><th style="text-align:left;">核心表现与局限性</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>空指针与边界溢出 (Edge Cases)</strong></td><td style="text-align:center;">🟢 <strong>极高</strong></td><td style="text-align:left;">擅长通过静态分析推断 <code>null/undefined</code> 风险、数组越界及死循环。</td></tr><tr><td style="text-align:left;"><strong>异步竞态与并发问题 (Race Conditions)</strong></td><td style="text-align:center;">🟢 <strong>极高</strong></td><td style="text-align:left;">能敏锐捕捉 Promise 遗漏 <code>await</code>、锁未释放、状态更新时序错乱等隐蔽 Bug。</td></tr><tr><td style="text-align:left;"><strong>类型一致性 (Type Safety)</strong></td><td style="text-align:center;">🟢 <strong>极高</strong></td><td style="text-align:left;">结合 TypeScript/Rust 等强类型语言的 AST，能精准发现隐式转换或泛型擦除问题。</td></tr><tr><td style="text-align:left;"><strong>测试用例遗漏 (Test Gaps)</strong></td><td style="text-align:center;">🟢 <strong>极高</strong></td><td style="text-align:left;">极其擅长根据业务代码的 Diff，反推并罗列未被覆盖的测试分支。</td></tr><tr><td style="text-align:left;"><strong>基础安全漏洞 (Security Flaws)</strong></td><td style="text-align:center;">🟡 <strong>中等</strong></td><td style="text-align:left;">能扫出明显的 SQL 注入、XSS 或硬编码密钥，但对复杂的“越权访问”逻辑无能为力，需人工复核。</td></tr><tr><td style="text-align:left;"><strong>业务策略与领域模型 (Domain Logic)</strong></td><td style="text-align:center;">🔴 <strong>极低</strong></td><td style="text-align:left;">无法判断代码是否真正符合产品需求（例如：“打折逻辑是否与双十一活动冲突”）。</td></tr><tr><td style="text-align:left;"><strong>全局架构取舍 (Architecture)</strong></td><td style="text-align:center;">🔴 <strong>极低</strong></td><td style="text-align:left;">缺乏全局上下文，无法判断引入某个第三方库是否违背了团队的技术栈演进方向。</td></tr></tbody></table><h2 id="二、工业级人机协同评审流-workflow" tabindex="-1">二、工业级人机协同评审流 (Workflow) <a class="header-anchor" href="#二、工业级人机协同评审流-workflow" aria-label="Permalink to &quot;二、工业级人机协同评审流 (Workflow)&quot;">​</a></h2>',6)),(a(),p(d,null,{default:t(()=>[s(r,{id:"mermaid-114",class:"mermaid",graph:"flowchart%20TD%0A%20%20A%5B%22%F0%9F%92%BB%20%E5%BC%80%E5%8F%91%E8%80%85%E6%8F%90%E4%BA%A4%20PR%20%2F%20Diff%22%5D%20--%3E%20B%5B%22%F0%9F%A4%96%20AI%20%E9%9D%99%E6%80%81%E5%88%9D%E7%AD%9B%E6%89%AB%E6%8F%8F%22%5D%0A%20%20B%20--%3E%20C%5B%22%F0%9F%93%8B%20AI%20%E8%BE%93%E5%87%BA%E7%BB%93%E6%9E%84%E5%8C%96%E9%A3%8E%E9%99%A9%E6%B8%85%E5%8D%95%22%5D%0A%20%20C%20--%3E%20D%7B%22%F0%9F%95%B5%EF%B8%8F%20%E4%BA%BA%E7%B1%BB%20Reviewer%20%E4%BB%B2%E8%A3%81%22%7D%0A%20%20D%20--%3E%7C%E8%AF%AF%E6%8A%A5%20(False%20Positive)%7C%20E%5B%22%E5%BF%BD%E7%95%A5%E8%AF%A5%E5%BB%BA%E8%AE%AE%22%5D%0A%20%20D%20--%3E%7C%E7%A1%AE%E8%AE%A4%E4%B8%BA%20Bug%20%2F%20%E9%9A%90%E6%82%A3%7C%20F%5B%22%E9%A9%B3%E5%9B%9E%E4%BF%AE%E6%94%B9%E6%88%96%E8%A1%A5%E5%85%85%E4%BB%A3%E7%A0%81%22%5D%0A%20%20F%20--%3E%20G%5B%22%F0%9F%A7%AA%20%E8%A1%A5%E5%85%85%E9%98%B2%E5%9B%9E%E5%BD%92%E6%B5%8B%E8%AF%95%22%5D%0A%20%20G%20--%3E%20H%5B%22%E2%9C%85%20%E9%87%8D%E6%96%B0%E9%AA%8C%E8%AF%81%E5%B9%B6%E5%90%88%E5%B9%B6%22%5D%0A%0A%20%20style%20B%20fill%3A%23e1f5fe%2Cstroke%3A%230288d1%0A%20%20style%20C%20fill%3A%23e1f5fe%2Cstroke%3A%230288d1%0A%20%20style%20D%20fill%3A%23fff3e0%2Cstroke%3A%23f57c00%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=n(`<h2 id="三、黄金-cr-提示词-prompt-模板" tabindex="-1">三、黄金 CR 提示词 (Prompt) 模板 <a class="header-anchor" href="#三、黄金-cr-提示词-prompt-模板" aria-label="Permalink to &quot;三、黄金 CR 提示词 (Prompt) 模板&quot;">​</a></h2><p>让 AI 做 Code Review 时，最怕它在“代码格式”和“主观风格”上长篇大论。必须用严格的 Prompt 约束它的行为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【角色设定】：你是一位严苛的资深架构师，正在进行代码评审 (Code Review)。</span></span>
<span class="line"><span>【审查目标】：请审视以下 Diff 代码，严格忽略所有关于代码风格（如缩进、变量命名规范）的讨论。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请仅从以下 5 个高优维度进行排查：</span></span>
<span class="line"><span>1. 明显的运行时 Bug（如空指针、死循环、未捕获异常）。</span></span>
<span class="line"><span>2. 历史逻辑的回归风险（是否破坏了现有的 API 契约）。</span></span>
<span class="line"><span>3. 异步并发与竞态条件风险。</span></span>
<span class="line"><span>4. 安全漏洞（如 XSS、注入、越权隐患、敏感信息硬编码）。</span></span>
<span class="line"><span>5. 缺失的关键边界测试用例。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【输出格式】：</span></span>
<span class="line"><span>针对发现的每一个问题，请严格按照以下结构输出：</span></span>
<span class="line"><span>- 📍 **位置**：[具体的文件名与行数]</span></span>
<span class="line"><span>- 💣 **风险**：[为什么这是一个问题，可能导致什么后果]</span></span>
<span class="line"><span>- 🛠️ **建议**：[具体的修复代码段]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h2 id="四、领域深度核对表-checklists" tabindex="-1">四、领域深度核对表 (Checklists) <a class="header-anchor" href="#四、领域深度核对表-checklists" aria-label="Permalink to &quot;四、领域深度核对表 (Checklists)&quot;">​</a></h2><p>不同端侧的代码，AI 关注的侧重点应当有所不同。你可以将以下清单作为 Context 喂给 AI。</p><h3 id="_4-1-前端交互与状态层-front-end" tabindex="-1">4.1 前端交互与状态层 (Front-end) <a class="header-anchor" href="#_4-1-前端交互与状态层-front-end" aria-label="Permalink to &quot;4.1 前端交互与状态层 (Front-end)&quot;">​</a></h3><ul class="task-list"><li class="task-list-item"><input type="checkbox" id="cbx_0" disabled="true"><label for="cbx_0"><strong>状态机完整性</strong>：异步请求的 <code>loading</code>、<code>error</code>、<code>empty</code>、<code>success</code> 四态是否全部闭环处理？</label></li><li class="task-list-item"><input type="checkbox" id="cbx_1" disabled="true"><label for="cbx_1"><strong>竞态拦截</strong>：多次极速点击同一个提交按钮，是否会导致重复请求？</label></li><li class="task-list-item"><input type="checkbox" id="cbx_2" disabled="true"><label for="cbx_2"><strong>内存泄漏</strong>：组件卸载 (Unmount) 时，定时器、事件监听器 (Event Listeners) 是否已清理？</label></li><li class="task-list-item"><input type="checkbox" id="cbx_3" disabled="true"><label for="cbx_3"><strong>防御性渲染</strong>：深层级对象访问（如 <code>user.profile.avatar</code>）是否加了可选链 <code>?.</code>？长列表是否会导致主线程卡顿？</label></li><li class="task-list-item"><input type="checkbox" id="cbx_4" disabled="true"><label for="cbx_4"><strong>组件契约</strong>：修改 <code>Props</code> 或 <code>Emits</code> 是否向后兼容？是否会导致消费该组件的其他页面崩溃？</label></li></ul><h3 id="_4-2-后端逻辑与-api-层-back-end" tabindex="-1">4.2 后端逻辑与 API 层 (Back-end) <a class="header-anchor" href="#_4-2-后端逻辑与-api-层-back-end" aria-label="Permalink to &quot;4.2 后端逻辑与 API 层 (Back-end)&quot;">​</a></h3><ul class="task-list"><li class="task-list-item"><input type="checkbox" id="cbx_5" disabled="true"><label for="cbx_5"><strong>防御性入参</strong>：所有来自外部的请求参数，是否经过了严格的 Schema 校验？</label></li><li class="task-list-item"><input type="checkbox" id="cbx_6" disabled="true"><label for="cbx_6"><strong>水平/垂直越权</strong>：查询或修改数据时，是否带入了当前登录用户的身份标识（如 <code>where user_id = ?</code>）？</label></li><li class="task-list-item"><input type="checkbox" id="cbx_7" disabled="true"><label for="cbx_7"><strong>接口幂等性</strong>：支付、创建订单等核心写接口，重试时是否会产生脏数据？</label></li><li class="task-list-item"><input type="checkbox" id="cbx_8" disabled="true"><label for="cbx_8"><strong>数据库事务</strong>：涉及多张表更新的逻辑，事务边界是否清晰？发生异常时是否正确 <code>rollback</code>？</label></li><li class="task-list-item"><input type="checkbox" id="cbx_9" disabled="true"><label for="cbx_9"><strong>外部依赖兜底</strong>：调用第三方 API 超时或报错时，是否有重试机制或优雅降级（Fallback）方案？</label></li></ul><h2 id="五、安全风险雷达-security-mindmap" tabindex="-1">五、安全风险雷达 (Security Mindmap) <a class="header-anchor" href="#五、安全风险雷达-security-mindmap" aria-label="Permalink to &quot;五、安全风险雷达 (Security Mindmap)&quot;">​</a></h2><p>在安全领域，AI 的定位是“报警器”，听到警报后，人类必须亲自排爆。</p>`,11)),(a(),p(d,null,{default:t(()=>[s(r,{id:"mermaid-194",class:"mermaid",graph:"mindmap%0A%20%20root((%F0%9F%9B%A1%EF%B8%8F%20AI%20%E5%AE%89%E5%85%A8%E5%AE%A1%E6%9F%A5%E9%9B%B7%E8%BE%BE))%0A%20%20%20%20%E6%9D%83%E9%99%90%E6%8E%A7%E5%88%B6%20(Auth)%0A%20%20%20%20%20%20%E6%B0%B4%E5%B9%B3%E8%B6%8A%E6%9D%83%20(BOLA)%0A%20%20%20%20%20%20%E6%9C%AA%E6%8E%88%E6%9D%83%E8%AE%BF%E9%97%AE%0A%20%20%20%20%20%20%E8%A7%92%E8%89%B2%E6%B7%B7%E6%B7%86%0A%20%20%20%20%E6%95%B0%E6%8D%AE%E5%A4%84%E7%90%86%20(Data)%0A%20%20%20%20%20%20%E6%95%8F%E6%84%9F%E6%95%B0%E6%8D%AE%E6%9C%AA%E8%84%B1%E6%95%8F%20(%E5%A6%82%E6%89%8B%E6%9C%BA%E5%8F%B7%2F%E5%AF%86%E7%A0%81)%0A%20%20%20%20%20%20%E6%97%A5%E5%BF%97%E6%B3%A8%E5%85%A5%20(Log%20Forging)%0A%20%20%20%20%20%20%E5%AF%86%E9%92%A5%E7%A1%AC%E7%BC%96%E7%A0%81%20(Hardcoded%20Secrets)%0A%20%20%20%20%E6%81%B6%E6%84%8F%E8%BE%93%E5%85%A5%20(Input)%0A%20%20%20%20%20%20XSS%20(%E8%B7%A8%E7%AB%99%E8%84%9A%E6%9C%AC)%0A%20%20%20%20%20%20SQL%20%E6%B3%A8%E5%85%A5%20%2F%20NoSQL%20%E6%B3%A8%E5%85%A5%0A%20%20%20%20%20%20%E4%BB%BB%E6%84%8F%E6%96%87%E4%BB%B6%E4%B8%8A%E4%BC%A0%20(RCE%20%E9%A3%8E%E9%99%A9)%0A%20%20%20%20%E9%AB%98%E5%8D%B1%E6%93%8D%E4%BD%9C%20(Ops)%0A%20%20%20%20%20%20%E7%89%A9%E7%90%86%E5%88%A0%E9%99%A4%20(%E6%9C%AA%E7%94%A8%E8%BD%AF%E5%88%A0%E9%99%A4)%0A%20%20%20%20%20%20%E9%87%91%E9%A2%9D%E8%AE%A1%E7%AE%97%E7%B2%BE%E5%BA%A6%E4%B8%A2%E5%A4%B1%20(%E6%B5%AE%E7%82%B9%E6%95%B0%E9%99%B7%E9%98%B1)%0A%20%20%20%20%20%20%E7%94%9F%E4%BA%A7%E7%8E%AF%E5%A2%83%E9%85%8D%E7%BD%AE%E6%9A%B4%E9%9C%B2%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[l(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=n(`<h2 id="六、反推测试缺口-test-gap-analysis" tabindex="-1">六、反推测试缺口 (Test Gap Analysis) <a class="header-anchor" href="#六、反推测试缺口-test-gap-analysis" aria-label="Permalink to &quot;六、反推测试缺口 (Test Gap Analysis)&quot;">​</a></h2><p>不要自己想测试用例，让 AI 看着 Diff 反推你漏掉了什么：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【指令】：请基于本次提交的 Diff，评估现有单元测试的覆盖缺口。</span></span>
<span class="line"><span>请按以下优先级列出必须补充的测试用例：</span></span>
<span class="line"><span>- P0 (阻断级)：若不覆盖将导致严重回归的场景。</span></span>
<span class="line"><span>- P1 (核心级)：新增逻辑的主流程 Happy Path。</span></span>
<span class="line"><span>- P2 (边界级)：极端输入、异步超时或错误抛出分支。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="七、延伸阅读" tabindex="-1">七、延伸阅读 <a class="header-anchor" href="#七、延伸阅读" aria-label="Permalink to &quot;七、延伸阅读&quot;">​</a></h2><ul><li><a href="https://google.github.io/eng-practices/review/" target="_blank" rel="noreferrer">Google 官方工程实践指南：Code Review</a></li><li><a href="https://docs.github.com/en/copilot/how-tos/use-copilot-agents/request-a-code-review/use-code-review" target="_blank" rel="noreferrer">GitHub Copilot 辅助 Code Review 实践</a></li><li><a href="https://owasp.org/www-project-top-ten/" target="_blank" rel="noreferrer">OWASP Top 10 安全漏洞清单</a></li></ul><blockquote><p><strong>一句话总结：</strong> 不要问 AI “这段代码好不好”，而是命令 AI “找出这段代码在并发、边界和安全上的漏洞”。</p></blockquote>`,6))])}const y=E(b,[["render",u]]);export{k as __pageData,y as default};
